-- ============================================================
-- Elite BBS Rims — Master Seed File
-- ============================================================
-- Includes: schema, admin user, site settings, all 101 products
-- Usage (phpMyAdmin): Import this file into your `elitebbs_db` database
-- Usage (CLI):  mysql -u YOUR_USER -p elitebbs_db < seed.sql
-- ============================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ------------------------------------------------------------
-- SCHEMA
-- ------------------------------------------------------------

CREATE TABLE IF NOT EXISTS products (
    id                INT           PRIMARY KEY AUTO_INCREMENT,
    name              VARCHAR(255)  NOT NULL,
    slug              VARCHAR(255)  UNIQUE NOT NULL,
    description       TEXT,
    short_description VARCHAR(500),
    price             DECIMAL(10,2) NOT NULL,
    sale_price        DECIMAL(10,2) DEFAULT NULL,
    sku               VARCHAR(100)  UNIQUE,
    stock             INT           DEFAULT 10,
    category          VARCHAR(100),
    brand             VARCHAR(100),
    size              VARCHAR(50),
    finish            VARCHAR(50),
    fitment_data      TEXT,
    images            JSON,
    featured          BOOLEAN       DEFAULT FALSE,
    status            ENUM('active','draft') DEFAULT 'active',
    created_at        TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
    updated_at        TIMESTAMP     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_status   (status),
    INDEX idx_category (category),
    INDEX idx_slug     (slug)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS orders (
    id               INT           PRIMARY KEY AUTO_INCREMENT,
    order_number     VARCHAR(50)   UNIQUE NOT NULL,
    customer_name    VARCHAR(100)  NOT NULL,
    customer_email   VARCHAR(100)  NOT NULL,
    customer_phone   VARCHAR(30),
    billing_address  TEXT,
    shipping_address TEXT,
    vehicle_make     VARCHAR(50),
    vehicle_model    VARCHAR(50),
    vehicle_year     VARCHAR(10),
    notes            TEXT,
    items_json       JSON          NOT NULL,
    subtotal         DECIMAL(10,2) DEFAULT 0,
    discount         DECIMAL(10,2) DEFAULT 0,
    shipping_cost    DECIMAL(10,2) DEFAULT 0,
    total            DECIMAL(10,2) NOT NULL,
    payment_method   VARCHAR(50)   DEFAULT 'email_transfer',
    status           ENUM('pending','processing','shipped','completed','cancelled') DEFAULT 'pending',
    created_at       TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
    updated_at       TIMESTAMP     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_order_number  (order_number),
    INDEX idx_status        (status),
    INDEX idx_customer_email(customer_email),
    INDEX idx_created_at    (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS order_items (
    id           INT           PRIMARY KEY AUTO_INCREMENT,
    order_id     INT           NOT NULL,
    product_id   INT,
    product_name VARCHAR(255)  NOT NULL,
    product_sku  VARCHAR(100),
    quantity     INT           NOT NULL DEFAULT 1,
    unit_price   DECIMAL(10,2) NOT NULL,
    total_price  DECIMAL(10,2) NOT NULL,
    FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE,
    INDEX idx_order_id (order_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS admins (
    id         INT          PRIMARY KEY AUTO_INCREMENT,
    username   VARCHAR(50)  UNIQUE NOT NULL,
    password   VARCHAR(255) NOT NULL,
    email      VARCHAR(100),
    full_name  VARCHAR(100),
    role       ENUM('super_admin','admin') DEFAULT 'admin',
    status     ENUM('active','inactive')   DEFAULT 'active',
    last_login TIMESTAMP NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_username (username),
    INDEX idx_status   (status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS site_settings (
    id            INT          PRIMARY KEY AUTO_INCREMENT,
    setting_key   VARCHAR(100) UNIQUE NOT NULL,
    setting_value TEXT,
    updated_at    TIMESTAMP    DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_setting_key (setting_key)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

